1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	interface QuoteResult {
17	  premium: number;
18	}
19	
20	interface ClaimResult {
21	  payout: number;
22	  remainingCap: number;
23	}
24	
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PRICE = 60;
27	
28	interface Item {
29	  type: string;
30	  enchantment?: number;
31	  cursed?: boolean;
32	}
33	
34	const CURSED_SURCHARGE_RATE = 0.5;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
37	const FIRST_INSURANCE_RATE = 0.1;
38	const LOYALTY_THRESHOLD = 2;
39	const LOYALTY_DISCOUNT_RATE = 0.2;
40	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
41	
42	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
43	
44	const itemSurcharge = (item: Item): number => {
45	  const base = basePremiumFor(item.type);
46	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
47	  const enchantmentSurcharge =
48	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
49	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
50	      : 0;
51	  return cursedSurcharge + enchantmentSurcharge;
52	};
53	
54	const countByType = (items: Array<Item>): Record<string, number> => {
55	  const counts: Record<string, number> = {};
56	  for (const item of items) {
57	    counts[item.type] = (counts[item.type] ?? 0) + 1;
58	  }
59	  return counts;
60	};
61	
62	const policyBasePremiumFor = (items: Array<Item>): number => {
63	  const typeCounts = countByType(items);
64	  return Object.entries(typeCounts).reduce(
65	    (total, [type, count]) =>
66	      total + (count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * basePremiumFor(type)),
67	    0,
68	  );
69	};
70	
71	const quotePremium = (customer: Customer, items: Array<Item>, quoteIndex: number): number => {
72	  const policyBasePremium = policyBasePremiumFor(items);
73	  const totalSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
74	  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
75	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD
76	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
77	    : 0;
78	  const followUpDiscount = quoteIndex > 0
79	    ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE
80	    : 0;
81	  const grossPremium = policyBasePremium + totalSurcharges + firstInsurance;
82	  const totalDiscounts = loyaltyDiscount + followUpDiscount;
83	  return Math.ceil(grossPremium - totalDiscounts + PROCESSING_FEE);
84	};
85	
86	const INSURANCE_VALUES: Record<string, number> = {
87	  sword: 1000,
88	  amulet: 600,
89	  staff: 800,
90	  potion: 400,
91	  rune: 250,
92	  moonstone: 250,
93	};
94	
95	const DEDUCTIBLE = 100;
96	const CAP_MULTIPLIER = 2;
97	
98	const processClaim = (
99	  policyItems: Array<Item>,
100	  damages: Array<{ itemType: string; amount: number }>,
101	): ClaimResult => {
102	  const insuranceSum = policyItems.reduce(
103	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0),
104	    0,
105	  );
106	  const cap = CAP_MULTIPLIER * insuranceSum;
107	  const totalPayout = damages.reduce(
108	    (sum, damage) => sum + Math.max(0, damage.amount - DEDUCTIBLE),
109	    0,
110	  );
111	  const cappedPayout = Math.min(totalPayout, cap);
112	  return {
113	    payout: Math.floor(cappedPayout),
114	    remainingCap: cap - cappedPayout,
115	  };
116	};
117	
118	export const processSteps = (customer: Customer, steps: Array<Record<string, unknown>>): Array<QuoteResult | ClaimResult> => {
119	  const policies: Array<Array<Item>> = [];
120	  return steps.map((step) => {
121	    if (step.op === "claim") {
122	      const policyIndex = step.policy as number;
123	      const incident = step.incident as { cause: string; damages: Array<{ itemType: string; amount: number }> };
124	      return processClaim(policies[policyIndex], incident.damages);
125	    }
126	    const items = step.items as Array<Item>;
127	    const result = {
128	      premium: quotePremium(customer, items, policies.length),
129	    };
130	    policies.push(items);
131	    return result;
132	  });
133	};
